head.script:
/**
 * 화 면 명 : 차량예약현황 및 등록 (차량예약)
 * 메뉴경로 : 공통/총무업무/업무용 차량관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ps/rc/fms/imgnt/rc_605_01_01b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-11-07
 * 수정이력  :
 *    - 2025-11-07      정승혜    최초작성
 *    - 2026-02-27      정승혜    기타수정
 * 메모 : 
 *  차량예약현황의 파랑색 일자를 클릭해야 차량예약 상세현황 정보가 조회됨
 *  바링딩때문에 dma_cond2 추가하여 서브미션 IN_DS1 분리처리
 * // 엑셀다운 4+8+16
 * DT협의내용
 * asis 는 관리부서,차량번호,차종명만 엑셀 다운되지만 tobe 는 날짜까지 다운되는점(그리드 그대로니까)
 * 엑셀다운에는 색상표현 안되는점(색상표현방식을 바꿨는데 이전방식으로는 색상다운이 되었지만 선택시 색상변경처리가 안되어 방식바꾼부분)
 * 차후 색상표현이 필요하여 추가작업되거나, 데이터만 표출하거나 방식으로 고려해보신다고 합니다 일단은 넘어가는것으로 협의하였습니다
 * 조회조건 : 202001
 */

scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strNowDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strNowDatePlus3 = "";
scwin.count = 0;

scwin.memJson = $c.data.getMemInfo(); // 세션정보
scwin.userId      = scwin.memJson.userId;
scwin.userNm      = scwin.memJson.userNm;
scwin.empNo 	  = scwin.memJson.empNo;
scwin.vEmpNo 	  = scwin.memJson.empNo;
scwin.empNm       = scwin.memJson.userNm;
scwin.acctDeptCd  = scwin.memJson.acctDeptCd;
scwin.acctDeptNm  = scwin.memJson.acctDeptNm;
scwin.deptNm  = scwin.memJson.deptNm;
scwin.occpgrdNm   = scwin.memJson.occpgrdNm;

scwin.notOncolumnChange = false;
scwin.upCd = "";
scwin.colNum = "";
scwin.strdate = "";
scwin.veqCd = "";
scwin.veqModelNms = "";    
scwin.today = scwin.strFromDate;
/* 
    for(i=1; i<30; i++){
		if(scwin.count<3){
            scwin.strNowDatePlus3 = WebSquare.date.dateAdd( scwin.sDate, i );
			WebSquare.date.is
	        if(scwin.sDate.isHoliday(scwin.strNowDatePlus3, true)){        	
	        }else{
	            scwin.count++;
	        }
	    }    
    }
    count 사용되는 구역 없음
 */

    //-------------------------------------------------------------------------
    // 화면로딩
    //-------------------------------------------------------------------------
scwin.onpageload = function() {
	const codeOptions = [
    { grpCd : "RC972", compID : "gr_vehclDetail:admitYn" },
    { grpCd : "RC977", compID : "lc_superUser" },
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_SetDtheader_results();
};

scwin.onUdcCompleted = function() {
    ed_yyyymm.setValue(scwin.strFromDate);
    ed_deptCd.setValue(scwin.acctDeptCd);
    ed_deptNm.setValue(scwin.acctDeptNm);

    $c.gus.cfDisableKey();

    if(scwin.userId =='kimseok'){
        ed_deptCd.setValue("00651");
        ed_deptNm.value ="외주구매";
    }
};

