    //-------------------------------------------------------------------------
    // 조회-차량예약현황 
    //-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {

    dma_cond.set("rsvDt", ed_yyyymm.getValue() );
    dma_cond.set("deptCd", ed_deptCd.getValue() );
    dma_cond.set("vehclNo", ed_vehclNo.getValue() );
    dma_cond.set("vehclNm", ed_vehclNm.getValue() );

    dma_cond2.set("rsvDt", ed_yyyymm.getValue() );
    dma_cond2.set("deptCd", ed_deptCd.getValue() );
    dma_cond2.set("vehclNo", ed_vehclNo.getValue() );
    dma_cond2.set("vehclNm", ed_vehclNm.getValue() );

    let ret = await $c.gus.cfValidate([ed_yyyymm]);
    if (!ret){
        return;
    }

    $c.sbm.execute(sbm_tr_retrieve);
};

    //-------------------------------------------------------------------------
    // 조회-차량예약상세현황
    //-------------------------------------------------------------------------
scwin.f_RsvDetailRetrieve = function() {
    $c.sbm.execute(sbm_tr_detail);
};

