    //호출되는곳 없음
};

    //-------------------------------------------------------------------------
    // 공통 PopUp 호출
    //-------------------------------------------------------------------------
scwin.f_OpenCommonPopUp = function(gubun, pCode, pName, pClose, pAllSearch, row) {
    let pWtitleSearch = null;
    if(gubun == 1){
        udc_workVehclInfo.cfCommonPopUp(
        scwin.udc_workVehclInfo_callBackFunc,
        pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,pWtitleSearch
        );
    }
    if(gubun == 4){
        udc_acctDeptCdInfo.cfCommonPopUp(
        scwin.udc_acctDeptCdInfo_callBackFunc,
        pCode,pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,pWtitleSearch
        );
    }
};

// 관리부서
scwin.udc_acctDeptCdInfo_onclickEvent = function (e) {
    scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'F', 'F');
};

// 관리부서
scwin.udc_acctDeptCdInfo_onviewchangeNameEvent = function (info) {
    if(ed_deptNm.getValue() != "" && ed_deptNm.getValue() != null){
        //scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'T', 'T');
        scwin.f_ChkOpenCommonPopUp(4, ed_deptNm, ed_deptCd, false);
    }
};

// 관리부서
scwin.udc_acctDeptCdInfo_onblurCodeEvent = function (e) {
    //scwin.f_OpenCommonPopUp(4, ed_deptCd.getValue(), ed_deptNm.getValue(), 'F', 'F');
    scwin.f_ChkOpenCommonPopUp(4, ed_deptCd, ed_deptNm);
};

// 차량번호
scwin.udc_workVehclInfo_onclickEvent = function (e) {
    scwin.f_OpenCommonPopUp(1, ed_vehclNo.getValue(), ed_vehclNm.getValue(), 'F', 'F');
};

// 차량번호
scwin.udc_workVehclInfo_onviewchangeNameEvent = function (info) {
    if(ed_vehclNm.getValue() != "" && ed_vehclNm.getValue() != null){
        //scwin.f_OpenCommonPopUp(1, ed_vehclNo.getValue(), ed_vehclNm.getValue(), 'T', 'T');
        scwin.f_ChkOpenCommonPopUp(1, ed_vehclNm, ed_vehclNo, false)
    }
};

// 차량번호
scwin.udc_workVehclInfo_onblurCodeEvent = function (e) {
