};

// 차량번호
scwin.udc_workVehclInfo_callBackFunc = function(rtnList) {
    if(rtnList != null && rtnList[0] != "N/A" ) {
        ed_vehclNo.setValue(rtnList[0]);
        ed_vehclNm.setValue(rtnList[1]);
    }
};

scwin.udc_acctDeptCdInfo_callBackFunc = function(rtnList) {
    if(rtnList != null && rtnList[0] != "N/A" ) {
        ed_deptCd.setValue(rtnList[0]); 
        ed_deptNm.setValue(rtnList[1]); 
    }
};

scwin.f_openCommonPopUp2 = function() {
    //호출되는곳 없음
};

    //-------------------------------------------------------------------------
    // 예약수정
    //------------------------------------------------------------------------- 
scwin.f_RsvPopup_Update = function() {
    let count = ds_out1.getRowCount();
    if(count == 0) { 
        return;
    } else {
        scwin.upCd="Y";
        scwin.f_RsvPopupOpen();
    }
};

    //-------------------------------------------------------------------------
    // 예약팝업 
    //------------------------------------------------------------------------- 
scwin.f_RsvPopupOpen = async function(rowIndex,columnId) {
    /*        
            현재일자 기준으로, 3일내에만 예약이 가능하다, 
    */

    // 예약을 위해 클릭한 날짜, 
    let cliecked_yyyymmdd = 0;

    if( columnId >= 10){
        cliecked_yyyymmdd = ed_yyyymm.getValue() + columnId;
    }
    else {
        cliecked_yyyymmdd = ed_yyyymm.getValue() + "0" + columnId;
    }

    // 현재일자,현재일자+3
    let nowDate      = scwin.strNowDate;
    let nowDatePlus3 = scwin.strNowDatePlus3;

    if( scwin.userId =="kimseok"){
        await $c.win.alert(
            "예약팝업클릭됨"
            +"\n"+"nowDate          => " + nowDate
            +"\n"+"nowDatePlus3     => " + nowDatePlus3
            +"\n"+"Clickedrow       => " + rowIndex
            +"\n"+"Clickedcolid     => " + columnId
            +"\n"+"ed_yyyymm.Text   => " + ed_yyyymm.getValue()
            +"\n"+"cliecked yyyymmdd=> " + cliecked_yyyymmdd
        );            
    }

    let findRow = -1;
    // superUser가 아니면 시간/날짜 체크
    for(let i=0; i< dlt_commonCodeRC977.getRowCount(); i++){
        if(dlt_commonCodeRC977.getCellData(0,"code") == scwin.vEmpNo){
            findRow++;
        }
    }

    if (findRow < 0 ) {	
        if( parseInt(nowDatePlus3) <= parseInt(cliecked_yyyymmdd) ) {
            await $c.win.alert("현재일자["+nowDate+"] 보다, 3일 초과일자는 예약이 불가능합니다.\n클릭한일자["+cliecked_yyyymmdd+"]");
            return;            	
        }
    }

    let row        = 0;
    let shortCd    = "";
    let vehclNo    = "";
    let eqCd       = "";
    let eqModelNms = "";        
    let deptCd     = "";        
    let ctrtNo     = "";
    let rsvSeq     = "";
    let rsvDt      = "";
    let admitYnCd  = 0;
    let url        = "";
    let data = {};


    if (ds_out.getRowCount() == 0) {
        await $c.win.alert("차량 예약 현황을 조회 후 날짜를 선택하여 예약/수정 하십시오.");
    } else {
        if (scwin.upCd == "N") { //신규등록
            row = ds_out.getRowPosition();

            vehclNo    = ds_out.getCellData(row,"vehclNo"     ); 
            ctrtNo     = ds_out.getCellData(row,"ctrtNo"      );
            shortCd    = ds_out.getCellData(row,"vehclShortCd");
            rsvDt      = ed_yyyymm.getValue() + scwin.colNum;
            rsvSeq     = ds_out.getCellData(row,"rsvSeq"      );
            eqCd       = ds_out.getCellData(row,"eqCd"        );
            eqModelNms = ds_out.getCellData(row,"eqModelNm"   );

            if( ds_out.getCellData(rowIndex,("col" + columnId ) ) > 0 && ds_out.getCellData(rowIndex,("admit" + columnId )) == 1  ){
                admitYnCd = "1";                
            }

            if( scwin.userId =="kimseok"){
                await $c.win.alert(
                           "vehclNo      =>"+vehclNo   
                    +"\n"+ "upCd         =>"+scwin.upCd            		               
                    +"\n"+ "ctrtNo       =>"+ctrtNo    
                    +"\n"+ "shortCd      =>"+shortCd   
                    +"\n"+ "rsvDt        =>"+rsvDt     
                    +"\n"+ "rsvSeq       =>"+rsvSeq    
                    +"\n"+ "eqCd         =>"+eqCd      
                    +"\n"+ "eqModelNms   =>"+eqModelNms
                    +"\n"+ "admitYnCd    =>"+admitYnCd
                    +"\n"+ "Clickedrow   =>"+rowIndex
                    +"\n"+ "Clickedcolid =>"+columnId
                );            
            }   
            deptCd = ds_out.getCellData(row,"deptCd");      
            data = {
                nowDate : nowDate,
                nowDatePlus3 : nowDatePlus3,

                vehclNo : vehclNo,
                vehclShortCd : shortCd,
                ctrtNo : ctrtNo,
                rsvDt : rsvDt,
                upCd : scwin.upCd,
                rsvSeq : rsvSeq,
                eqCd : eqCd,
                eqModelNms : eqModelNms,
                deptCd : deptCd,
                admitYnCd : admitYnCd
            };
        // 예약수정    
        }else if(scwin.upCd == "Y"){
            row = ds_out1.getRowPosition();

            vehclNo    = ds_out1.getCellData(row,"vehclNo"     );
            ctrtNo     = ds_out1.getCellData(row,"ctrtNo"      );
            rsvSeq     = ds_out1.getCellData(row,"rsvSeq"      );
            shortCd    = ds_out.getCellData( row,"vehclShortCd");
            rsvDt      = ds_out1.getCellData(row,"dptIntendDt" ).substring(0,8);
            eqCd       = scwin.veqCd;
            eqModelNms = scwin.veqModelNms;
            admitYnCd  = ds_out1.getCellData(row,"admitYn"); 

            if( scwin.userId =="kimseok"){
                await $c.win.alert(
                           "vehclNo      =>"+vehclNo   
                    +"\n"+ "ctrtNo       =>"+ctrtNo    
                    +"\n"+ "upCd         =>"+scwin.upCd            		               
                    +"\n"+ "shortCd      =>"+shortCd   
                    +"\n"+ "rsvDt        =>"+rsvDt     
                    +"\n"+ "rsvSeq       =>"+rsvSeq    
                    +"\n"+ "eqCd         =>"+eqCd      
                    +"\n"+ "eqModelNms   =>"+eqModelNms
                    +"\n"+ "admitYnCd    =>"+admitYnCd
                    +"\n"+ "Clickedrow   =>"+rowIndex
                    +"\n"+ "Clickedcolid =>"+columnId
                );            
            }

            data = {
                nowDate : nowDate,
                nowDatePlus3 : nowDatePlus3,

                vehclNo : vehclNo,
                vehclShortCd : shortCd,
                upCd : scwin.upCd,
                ctrtNo : ctrtNo,
                rsvDt : rsvDt,
                rsvSeq : rsvSeq,
                eqCd : eqCd,
                eqModelNms : eqModelNms,
                deptCd : deptCd,
                admitYnCd : admitYnCd
            };
        }
        let opt = {};
        opt.width = "800";
        opt.height = "500";
        opt.modal = true;
        opt.title = "title";
        opt.id = "popup";
        opt.popupName = "차량예약";

        //상세화면 호출 
        let valueObject = new Object();
        let result = await $c.win.openPopup("/ui/ps/rc/fms/imgnt/rc_605_01_01p.xml", opt, data);  // 파일없음
        if(result != '["N/A"]'){
            scwin.f_Retrieve();
        }
    }
};

    //-------------------------------------------------------------------------
    // 조회 필드 Clear(휴지통)
    //-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_cndArea, null);
    ed_yyyymm.setValue(scwin.strFromDate);
};

scwin.getMonthDay = function() {
    //Date 함수 사용으로 전환
};

scwin.getLeapYearFebruary = function() {
    //Date 함수 사용으로 전환
};

scwin.colRollback = function() {
    for (let i=1; i<32; i++) {
        gr_vehclRunList.setColumnVisible(i+"",true);
    }
    return true;
};

scwin.f_ChkOpenCommonPopUp = async function(gubun, inObj, pairObj, isCode) {
	//값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
	if(! await $c.gus.cfCanOpenPopup(inObj, pairObj))	
        return;

	//짝이 되는 오브젝트의 값 제거
	await $c.gus.cfClearPairObj(pairObj);

	//검색어 세팅
	let pVal = await $c.gus.cfGetValue(inObj);

	//inObj가 코드 필드일 경우 팝업
	if (isCode == null || isCode == true){
	    scwin.f_OpenCommonPopUp(gubun, pVal, '', 'T', 'T');	   
	}else{ //inObj가 코드명 필드일 경우 팝업
	    scwin.f_OpenCommonPopUp(gubun, '', pVal, 'T', 'T');
	}    
};

// grid decode format
scwin.grDisplayFm = function(data, formattedData, rowIndex, colIndex, type) {
    let columnId = "col";
    let admitId = "admit";

    if(this != null && this != "" && colIndex != null && colIndex != ""){
        columnId += gr_vehclRunList.getColumnID(colIndex);
        admitId += gr_vehclRunList.getColumnID(colIndex);
    }

    let tempData = data;
    let tempDataCol = ds_out.getCellData(rowIndex, columnId);
    let tempDataAdmit = ds_out.getCellData(rowIndex, admitId);

    if(type != "new"){
        if(tempDataCol > 0){
            if(tempDataAdmit != 1){
                gr_vehclRunList.setCellBackgroundColor(rowIndex, gr_vehclRunList.getColumnID(colIndex), "blue !important");
                //tempData = "<span class='bg-span-blue'>" + tempData + "</span>";

            }else{
                gr_vehclRunList.setCellBackgroundColor(rowIndex, gr_vehclRunList.getColumnID(colIndex), "red !important");
                //tempData = "<span class='bg-span-red'>" + tempData + "</span>";
            }
        }else{
            gr_vehclRunList.setCellBackgroundColor(rowIndex, gr_vehclRunList.getColumnID(colIndex), "");
        }
    }else{
        if(gr_vehclRunList.getColumnID(colIndex) == "deptNm" || gr_vehclRunList.getColumnID(colIndex) == "vehclNo" || gr_vehclRunList.getColumnID(colIndex) == "eqModelNm"){

        }else{
            gr_vehclRunList.setCellBackgroundColor(rowIndex, gr_vehclRunList.getColumnID(colIndex), "lightblue !important");
        }
    }

    return tempData; 
}

// 차량예약현황
scwin.gr_vehclRunList_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    scwin.grDisplayFm("", "", rowIndex, columnIndex, "new");
    scwin.grDisplayFm("", "", oldRow, oldColumnIndex, "old");

    //차량예약현황을 click한 후 차량예약버튼 클릭
    let colId = gr_vehclRunList.getColumnID(columnIndex);

	scwin.upCd="N";   
	if (colId<10){
	    scwin.colNum = "0"+colId;
	}else {
	    scwin.colNum = colId;
	}

    //oncellclick
    let vday= "";
    if(colId < 10){
        vday = "0" + colId;
    } else {
        vday = colId;
    }

    scwin.strdate = ed_yyyymm.getValue() + vday; 

    let vehclNo = ds_out.getCellData(ds_out.getRowPosition(), "vehclNo");
    let ctrtNo = ds_out.getCellData(ds_out.getRowPosition(), "ctrtNo");
    scwin.veqCd = ds_out.getCellData(ds_out.getRowPosition(), "eqCd");
    scwin.veqModelNms = ds_out.getCellData(ds_out.getRowPosition(), "eqModelNm");

    scwin.f_RsvDetailRetrieve(ds_out.getRowPosition(),vehclNo,ctrtNo,scwin.strdate);   
};

// 차량예약현황
scwin.gr_vehclRunList_oncellclick = function (rowIndex, columnIndex, columnId) {
    let vday= "";
    if(columnId < 10){
        vday = "0" + columnId;
    } else {
        vday = columnId;
    }

    scwin.strdate = ed_yyyymm.getValue() + vday; 

    let vehclNo = ds_out.getCellData(rowIndex, "vehclNo");
    let ctrtNo = ds_out.getCellData(rowIndex, "ctrtNo");
    scwin.veqCd = ds_out.getCellData(rowIndex, "eqCd");
    scwin.veqModelNms = ds_out.getCellData(rowIndex, "eqModelNm");

    scwin.f_RsvDetailRetrieve(rowIndex,vehclNo,ctrtNo,scwin.strdate);   
};

scwin.f_RsvDetailRetrieve = function(row,vehclNo,ctrtNo,strdate) {
    dma_cond.set("rsvDt" , strdate);
    dma_cond.set("ctrtNo" , ctrtNo);

    dma_cond2.set("vehclNo" , vehclNo);
    dma_cond2.set("rsvDt" , strdate);
    dma_cond2.set("ctrtNo" , ctrtNo);    

    $c.sbm.execute(sbm_tr_detail);
};

// 차량예약현황
scwin.gr_vehclRunList_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    // 승인완료상태의 차량은 차량별 실적등록화면으로 포워딩
    if(ds_out.getCellData(rowIndex, "admit"+columnId ) == 1){
        $c.gus.cfAlertMsg("승인완료된 건입니다.\n차량별운행실적등록화면으로 이동합니다.");

        let deptCd = ds_out.getCellData(rowIndex, "deptCd");    // 관리부서코드 
        let vehclNo = ds_out.getCellData(rowIndex, "vehclNo");  // 차량번호
        let yyyymm = ed_yyyymm.getValue();                      // 예약년월

        let data = {
            MOD : "TabAdded",
            deptCd : deptCd,
            vehclNo : vehclNo,
            yyyymm : yyyymm
        };

        //길어서 스크립트 오류남
        //let deptCdFlag = deptCd+vehclNo+yyyymm;
        let deptCdFlag = deptCd;

        let url = "/ui/ps/rc/fms/imgnt/rc_605_01_03b.xml";  
        $c.win.openMenu('차량별운행실적등록', url,url.substring(url.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp",data,{menuCode : deptCdFlag, menuCode2 : "new" });

    }else{
        scwin.upCd = "N";
        scwin.f_RsvPopupOpen(rowIndex,columnId);
    }

};

scwin.sbm_tr_detail_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows2.setValue(ds_out1.getRowCount());
    gr_vehclDetail.setFocusedCell(0,"rsvDtm",false)
};

scwin.sbm_tr_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows.setValue(ds_out.getRowCount());
    gr_vehclRunList.setFocusedCell(0,"deptNm",false)

    if( ds_out.getRowCount() == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    }

    let ret = await scwin.colRollback();

    let cal = ed_yyyymm.getValue();
    let cnt = new Date(cal.substr(0,4),cal.substr(4,2),0).getDate();
    if (ret){
        for(let i=cnt+1; i<=31; i++){
            gr_vehclRunList.setColumnVisible(i+"",false);
        }
    }
};

// 차량예약 상세현황
scwin.gr_vehclDetail_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    scwin.upCd="Y";
    scwin.f_RsvPopupOpen();
};

// 차량예약 상세현황
scwin.gr_vehclDetail_oncellclick = function (rowIndex, columnIndex, columnId) {
    //차량예약현황을 click한 후 차량예약버튼 클릭
	scwin.upCd="Y";
};

